export interface Role {
  id: string;
  name: string;
  inherits: string[];
}

export interface PermissionGrant {
  id: string;
  roleId: string;
  resource: string;
  action: string;
  effect: 'allow' | 'deny';
  startTime: number | null;
  endTime: number | null;
}

export interface UserRoleAssignment {
  userId: string;
  roleId: string;
  startTime: number | null;
  endTime: number | null;
}

export interface AccessCheckResult {
  allowed: boolean;
  reason: string;
  matchedGrants: string[];
}

export class RBACError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'RBACError';
  }
}

export function createRBAC() {
  const roles = new Map<string, Role>();
  const grants = new Map<string, PermissionGrant>();
  const userRoleAssignments = new Map<string, UserRoleAssignment[]>();

  function isGrantActive(grant: PermissionGrant, checkTime: number): boolean {
    const startOk = grant.startTime === null || grant.startTime <= checkTime;
    const endOk = grant.endTime === null || grant.endTime > checkTime;
    return startOk && endOk;
  }

  function isAssignmentActive(assignment: UserRoleAssignment, checkTime: number): boolean {
    const startOk = assignment.startTime === null || assignment.startTime <= checkTime;
    const endOk = assignment.endTime === null || assignment.endTime > checkTime;
    return startOk && endOk;
  }

  function isResourceMatched(grantResource: string, requestedResource: string): boolean {
    if (grantResource === '*') return true;
    return grantResource === requestedResource;
  }

  function isActionMatched(grantAction: string, requestedAction: string): boolean {
    if (grantAction === '*') return true;
    return grantAction === requestedAction;
  }

  function getRoleHierarchy(roleId: string, visited = new Set<string>()): Set<string> {
    if (visited.has(roleId)) {
      return new Set<string>();
    }
    visited.add(roleId);

    const result = new Set<string>();
    result.add(roleId);

    const role = roles.get(roleId);
    if (role) {
      for (const inheritedId of role.inherits) {
        const inherited = getRoleHierarchy(inheritedId, visited);
        inherited.forEach(r => result.add(r));
      }
    }

    return result;
  }

  function detectInheritanceCycle(): string[] | null {
    const visited = new Set<string>();
    const recursionStack = new Set<string>();

    function hasCycle(roleId: string, path: string[]): string[] | null {
      visited.add(roleId);
      recursionStack.add(roleId);
      path.push(roleId);

      const role = roles.get(roleId);
      if (role) {
        for (const inheritedId of role.inherits) {
          if (!visited.has(inheritedId)) {
            const cycle = hasCycle(inheritedId, [...path]);
            if (cycle) return cycle;
          } else if (recursionStack.has(inheritedId)) {
            const cycleStart = path.indexOf(inheritedId);
            return path.slice(cycleStart).concat([inheritedId]);
          }
        }
      }

      recursionStack.delete(roleId);
      return null;
    }

    for (const roleId of roles.keys()) {
      if (!visited.has(roleId)) {
        const cycle = hasCycle(roleId, []);
        if (cycle) return cycle;
      }
    }

    return null;
  }

  return {
    createRole(role: Role): void {
      if (!role.id || role.id.trim() === '') {
        throw new RBACError('Role ID must be non-empty');
      }
      if (roles.has(role.id)) {
        throw new RBACError(`Role with ID ${role.id} already exists`);
      }
      for (const inheritedId of role.inherits) {
        if (!roles.has(inheritedId)) {
          throw new RBACError(`Inherited role ${inheritedId} does not exist`);
        }
      }
      roles.set(role.id, role);
    },

    addGrant(grant: PermissionGrant): void {
      if (grants.has(grant.id)) {
        throw new RBACError(`Grant with ID ${grant.id} already exists`);
      }
      if (!roles.has(grant.roleId)) {
        throw new RBACError(`Role ${grant.roleId} does not exist`);
      }
      if (grant.startTime !== null && grant.endTime !== null && grant.startTime >= grant.endTime) {
        throw new RBACError('Grant startTime must be less than endTime');
      }
      grants.set(grant.id, grant);
    },

    revokeGrant(grantId: string): void {
      grants.delete(grantId);
    },

    assignRole(assignment: UserRoleAssignment): void {
      if (!roles.has(assignment.roleId)) {
        throw new RBACError(`Role ${assignment.roleId} does not exist`);
      }
      if (assignment.startTime !== null && assignment.endTime !== null && assignment.startTime >= assignment.endTime) {
        throw new RBACError('Assignment startTime must be less than endTime');
      }
      if (!userRoleAssignments.has(assignment.userId)) {
        userRoleAssignments.set(assignment.userId, []);
      }
      userRoleAssignments.get(assignment.userId)!.push(assignment);
    },

    unassignRole(userId: string, roleId: string): void {
      const assignments = userRoleAssignments.get(userId);
      if (assignments) {
        const filtered = assignments.filter(a => a.roleId !== roleId);
        if (filtered.length === 0) {
          userRoleAssignments.delete(userId);
        } else {
          userRoleAssignments.set(userId, filtered);
        }
      }
    },

    check(userId: string, resource: string, action: string, checkTime: number): AccessCheckResult {
      const cycle = detectInheritanceCycle();
      if (cycle) {
        throw new RBACError(`Circular role inheritance detected: ${cycle.join(' -> ')}`);
      }

      const assignments = userRoleAssignments.get(userId) || [];
      const activeRoles = new Set<string>();

      for (const assignment of assignments) {
        if (isAssignmentActive(assignment, checkTime)) {
          activeRoles.add(assignment.roleId);
        }
      }

      const allRoles = new Set<string>();
      for (const roleId of activeRoles) {
        const hierarchy = getRoleHierarchy(roleId);
        hierarchy.forEach(r => allRoles.add(r));
      }

      const matchedGrantIds: string[] = [];
      let hasDeny = false;
      let hasAllow = false;

      for (const grant of grants.values()) {
        if (!allRoles.has(grant.roleId)) continue;
        if (!isGrantActive(grant, checkTime)) continue;
        if (!isResourceMatched(grant.resource, resource)) continue;
        if (!isActionMatched(grant.action, action)) continue;

        matchedGrantIds.push(grant.id);
        if (grant.effect === 'deny') {
          hasDeny = true;
        } else {
          hasAllow = true;
        }
      }

      if (hasDeny) {
        return {
          allowed: false,
          reason: 'Access denied by explicit deny rule',
          matchedGrants: matchedGrantIds,
        };
      }

      if (hasAllow) {
        return {
          allowed: true,
          reason: 'Access allowed by permission grant',
          matchedGrants: matchedGrantIds,
        };
      }

      return {
        allowed: false,
        reason: 'No matching permission grants found',
        matchedGrants: matchedGrantIds,
      };
    },

    getEffectivePermissions(userId: string, atTime: number): {
      resource: string;
      action: string;
      effect: 'allow' | 'deny';
      grantId: string;
      viaRole: string;
    }[] {
      const assignments = userRoleAssignments.get(userId) || [];
      const activeRoles = new Set<string>();

      for (const assignment of assignments) {
        if (isAssignmentActive(assignment, atTime)) {
          activeRoles.add(assignment.roleId);
        }
      }

      const allRoles = new Set<string>();
      for (const roleId of activeRoles) {
        const hierarchy = getRoleHierarchy(roleId);
        hierarchy.forEach(r => allRoles.add(r));
      }

      const seenGrantIds = new Set<string>();
      const result: {
        resource: string;
        action: string;
        effect: 'allow' | 'deny';
        grantId: string;
        viaRole: string;
      }[] = [];

      for (const grant of grants.values()) {
        if (seenGrantIds.has(grant.id)) continue;
        if (!allRoles.has(grant.roleId)) continue;
        if (!isGrantActive(grant, atTime)) continue;

        seenGrantIds.add(grant.id);
        result.push({
          resource: grant.resource,
          action: grant.action,
          effect: grant.effect,
          grantId: grant.id,
          viaRole: grant.roleId,
        });
      }

      return result;
    },

    getUserRoles(userId: string, atTime: number): string[] {
      const assignments = userRoleAssignments.get(userId) || [];
      const activeRoles = new Set<string>();

      for (const assignment of assignments) {
        if (isAssignmentActive(assignment, atTime)) {
          activeRoles.add(assignment.roleId);
        }
      }

      const allRoles = new Set<string>();
      for (const roleId of activeRoles) {
        const hierarchy = getRoleHierarchy(roleId);
        hierarchy.forEach(r => allRoles.add(r));
      }

      return Array.from(allRoles);
    },

    detectInheritanceCycle,
  };
}
